describe("FormData class",()=>{it("should append and get string values",()=>{let e=new FormData;e.append("name","Alice"),e.append("age","30"),expect(e.get("name")).toEqual("Alice"),expect(e.get("age")).toEqual("30")}),it("should store Blob and File values correctly",()=>{let e=new FormData,t=new Blob(["hello"],{type:"text/plain"}),a=new File(["123"],"test.txt",{type:"text/plain"});e.append("blob",t),e.append("file",a),expect(e.get("blob")).toBeInstanceOf(Blob),expect(e.get("file")).toBeInstanceOf(File),expect(e.get("file").name).toEqual("test.txt")}),it("should overwrite existing keys when set() is used",()=>{let e=new FormData;e.append("color","red"),e.set("color","blue"),expect(e.get("color")).toEqual("blue")}),it("should delete an entry when delete() is called",()=>{let e=new FormData;e.append("token","abc123"),expect(e.has("token")).toBeTruthy(),e.delete("token"),expect(e.has("token")).toBeFalsy()}),it("should correctly report if a key exists using has()",()=>{let e=new FormData;e.append("flag","true"),expect(e.has("flag")).toBeTruthy(),expect(e.has("missing")).toBeFalsy()}),it("should return all keys with keys()",()=>{let e=new FormData;e.append("a","1"),e.append("b","2");let t=e.keys();expect(t).toContain("a"),expect(t).toContain("b")}),it("should return all values with values()",()=>{let e=new FormData;e.append("a","apple"),e.append("b","banana");let t=e.values();expect(t).toContain("apple"),expect(t).toContain("banana")}),it("should iterate entries() properly",()=>{let e=new FormData;e.append("x","100"),e.append("y","200");let t=Array.from(e.entries());expect(t).toEqual([["x","100"],["y","200"]])}),it("should call forEach() for all entries in order",()=>{let e=new FormData;e.append("a","1"),e.append("b","2");let t=[];e.forEach((a,n)=>{t.push([n,a])}),expect(t).toEqual([["a","1"],["b","2"]])}),it("should handle multiple values for the same key using append()",()=>{let e=new FormData;e.append("tag","news"),e.append("tag","tech");let t=e.getAll("tag");expect(t).toEqual(["news","tech"])})});
